// Honcho conclusion 기록: 사안↔WP 매핑
// 활동 기록 계약 형식 (고정)
const analysis = $('RA 응답 파싱').first().json;
const parsed = $node['본문 파싱 및 규제권 라우팅'].json;
let layer4 = {};
try {
  layer4 = $('Layer 4 컨텍스트 주입').first().json || {};
} catch (e) {
  layer4 = {};
}

const activityRecord = {
  ts: new Date().toISOString(),
  type: analysis.match === 'existing' ? 'matched' : 'matched',
  actor: analysis.actor,
  payload: {
    wp: analysis.wp,
    match: analysis.match,
    confidence: analysis.confidence,
    region: analysis.region,
    matching_key: parsed.matching_key,
    original_subject: parsed.original_subject,
    email_id: parsed.email_id,
    layer4_status: layer4.layer4_status || null,
    layer4_result_counts: layer4.layer4_result_counts || null
  }
};

const mailRecord = {
  ts: parsed.received_at,
  type: 'mail_received',
  actor: 'system',
  payload: {
    region: analysis.region,
    subject: parsed.original_subject,
    email_id: parsed.email_id,
    target: analysis.actor,
    layer4_status: layer4.layer4_status || null
  }
};

return [{ json: { activity_record: activityRecord, mail_record: mailRecord, analysis } }];

// Yellow 게이트: routing / parse / confidence 사유를 사람 검토 payload로 표준화
const parsed = $input.item.json;
let routing = {};
try {
  routing = $('본문 파싱 및 규제권 라우팅').first().json || {};
} catch (e) {
  routing = {};
}

const routingStatus = parsed.routing_status || routing.routing_status || 'unknown';
const matchedRegions = parsed.matched_regions || routing.matched_regions || [];
let yellowReason = parsed.yellow_reason || null;
let reason;

if (parsed.parse_error) {
  yellowReason = yellowReason || 'parse_error';
  reason = yellowReason === 'missing_fields'
    ? 'RA 응답 필수 필드 누락: ' + (parsed.missing_fields || []).join(', ')
    : yellowReason === 'invalid_confidence'
      ? 'RA 응답 confidence 값이 0.0-1.0 범위를 벗어남'
      : 'RA 응답 JSON 파싱 실패 — 사람 검토 필요';
} else if (yellowReason === 'low_confidence') {
  reason = 'RA 분석 confidence가 Yellow 임계값 미만 — 사람 검토 필요';
} else if (yellowReason === 'threshold_unconfigured') {
  reason = 'YELLOW_CONFIDENCE_THRESHOLD 미설정/비정상 — 보수적으로 사람 검토 필요';
} else if (yellowReason === 'wp_closed_or_done') {
  reason = parsed.yellow_detail || '매칭된 WP가 완료/종결 상태 — 사람 검토 필요';
} else if (yellowReason === 'wp_status_lookup_failed') {
  reason = parsed.yellow_detail || 'OpenProject WP 상태 조회 실패 — 사람 검토 필요';
} else if (yellowReason === 'wp_status_unknown') {
  reason = parsed.yellow_detail || 'OpenProject WP 상태가 허용 목록에 없음 — 사람 검토 필요';
} else if (yellowReason === 'wp_id_missing') {
  reason = parsed.yellow_detail || '기존 WP 매칭 결과에 WP ID가 없음 — 사람 검토 필요';
} else if (routingStatus === 'yellow_no_region') {
  yellowReason = 'yellow_no_region';
  reason = '규제기관 미판별 — 수동 배정 필요';
} else if (routingStatus === 'yellow_multi_region') {
  yellowReason = 'yellow_multi_region';
  reason = '복수 규제권 감지(' + matchedRegions.map(r => r.region).join(', ') + ') — 담당 지정 필요';
} else {
  yellowReason = yellowReason || 'manual_review_required';
  reason = '사람 검토 필요';
}

return [{
  json: {
    alert_type: 'yellow_gate',
    yellow_reason: yellowReason,
    reason,
    routing_status: routingStatus,
    original_subject: parsed.original_subject || routing.original_subject,
    original_from: parsed.original_from || routing.original_from,
    matching_key: parsed.matching_key || routing.matching_key,
    body_excerpt: parsed.body_excerpt || routing.body_excerpt,
    email_id: parsed.email_id || routing.email_id,
    matched_regions: matchedRegions,
    analysis: parsed.analysis || {
      actor: parsed.actor,
      wp: parsed.wp,
      match: parsed.match,
      confidence: parsed.confidence,
      region: parsed.region,
      comment: parsed.comment,
      transition_proposed: parsed.transition_proposed
    },
    missing_fields: parsed.missing_fields || [],
    parse_error: Boolean(parsed.parse_error),
    error: parsed._error || null,
    yellow_gate: parsed.yellow_gate || null,
    op_wp_status: parsed.op_wp_status || null,
    yellow_detail: parsed.yellow_detail || null,
    requires_human: true
  }
}];

// Yellow alert payload — 운영 채널 설정이 있으면 후속 전송 노드가 사용할 수 있게 표준화
const alert = $input.item.json;
const env = (typeof process !== 'undefined' && process.env) ? process.env : {};
const targetEmail = env.HUMAN_ALERT_EMAIL || null;
const targetWebhook = env.HUMAN_ALERT_WEBHOOK_URL || null;

const humanAlert = {
  ts: new Date().toISOString(),
  type: 'yellow_gate',
  actor: 'system',
  payload: alert
};

const delivery = {
  email: targetEmail,
  webhook: targetWebhook,
  status: targetWebhook
    ? 'webhook_configured'
    : targetEmail
      ? 'email_configured'
      : 'no_alert_channel_configured'
};

console.warn('[YELLOW ALERT]', JSON.stringify({
  reason: alert.yellow_reason,
  subject: alert.original_subject,
  delivery: delivery.status
}));

return [{
  json: {
    ...alert,
    human_alert: humanAlert,
    delivery,
    _yellow_alert: true,
    _yellow_alert_ready: Boolean(targetEmail || targetWebhook)
  }
}];

// Merge Honcho AI peer context with routing data for warm-start
const routingData = $('라우팅 게이트').item.json;
const contextData = $input.item.json;

const peerRepresentation = contextData.representation || '';

let warmStartBlock = '';
if (peerRepresentation && peerRepresentation.trim()) {
  warmStartBlock = '\n--- PAST EXPERIENCE (from memory) ---\n' + peerRepresentation + '\n--- END PAST EXPERIENCE ---';
}

return {
  ...routingData,
  warm_start_context: warmStartBlock,
  has_past_context: warmStartBlock.length > 0
};

// 기존 WP 상태 검증: 미완료 WP에만 자율 코멘트 허용
const analysis = $('RA 응답 파싱').first().json;
const wpResponse = $input.item.json || {};
const statusTitleRaw = (
  wpResponse.status?.title
  || wpResponse.status?.name
  || wpResponse._embedded?.status?.title
  || wpResponse._embedded?.status?.name
  || wpResponse._links?.status?.title
  || wpResponse._links?.status?.name
  || ''
);
const statusTitle = String(statusTitleRaw).toLowerCase();
const wpId = analysis.wp ? String(analysis.wp).replace('WP-', '') : null;

const closedPatterns = ['closed', 'done', 'complete', 'completed', '완료', '종결', '닫힘'];
const openPatterns = ['open', 'new', 'progress', 'review', '오픈', '진행', '리뷰', '검토'];
const lookupFailed = Boolean(wpResponse.error || wpResponse.message?.includes?.('error') || !wpResponse.id);
const isClosed = closedPatterns.some((p) => statusTitle.includes(p));
const isOpenLike = openPatterns.some((p) => statusTitle.includes(p));

let wpStatusAllowed = true;
let yellowReason = null;
let reason = null;

if (!wpId) {
  wpStatusAllowed = false;
  yellowReason = 'wp_id_missing';
  reason = '기존 WP 매칭 결과에 WP ID가 없어 사람 검토 필요';
} else if (lookupFailed) {
  wpStatusAllowed = false;
  yellowReason = 'wp_status_lookup_failed';
  reason = 'OpenProject WP 상태 조회 실패 — 신규 생성/코멘트 전 사람 검토 필요';
} else if (isClosed) {
  wpStatusAllowed = false;
  yellowReason = 'wp_closed_or_done';
  reason = '매칭된 WP가 완료/종결 상태 — 재오픈 또는 신규 처리 여부 사람 판단 필요';
} else if (!isOpenLike) {
  wpStatusAllowed = false;
  yellowReason = 'wp_status_unknown';
  reason = '매칭된 WP 상태가 허용 목록에 없어 사람 검토 필요: ' + (statusTitleRaw || 'unknown');
}

return [{
  json: {
    ...analysis,
    wp_status_allowed: wpStatusAllowed,
    yellow_required: !wpStatusAllowed,
    yellow_reason: yellowReason,
    yellow_detail: reason,
    op_wp_status: {
      wp_id: wpId,
      status_title: statusTitleRaw || null,
      lookup_failed: lookupFailed,
      is_closed: isClosed,
      is_open_like: isOpenLike,
      allowed_patterns: openPatterns,
      blocked_patterns: closedPatterns
    }
  }
}];

// Prepare Layer 4 real-time regulatory lookup.
// This node preserves warm-start data and builds a bounded query for hermes-api-server.
const data = $input.item.json;
const queryParts = [
  data.original_subject,
  data.matching_key,
  data.body_excerpt
].filter(Boolean);
const layer4Query = queryParts.join(' ').slice(0, 800);
return [{
  json: {
    ...data,
    layer4_query: layer4Query,
    layer4_profile: data.primary_actor || data.actor || 'ra_us',
    layer4_requested: Boolean(layer4Query)
  }
}];

// Merge Layer 4 lookup result back into the RA prompt input.
// Lookup failure must not stop RA processing; it becomes an explicit degraded context note.
let base = {};
try {
  base = $('Layer 4 조회 준비').first().json || {};
} catch (e) {
  base = {};
}
const lookup = $input.item.json || {};
const results = lookup.results || {};
const sections = [];

function addList(title, items, formatter) {
  if (!Array.isArray(items) || items.length === 0) return;
  sections.push(title);
  items.slice(0, 3).forEach((item, idx) => sections.push('[' + (idx + 1) + '] ' + formatter(item)));
}

addList('Layer 4 llm-wiki results', results.llm_wiki, (item) => {
  return [item.path || item.source || '', item.excerpt || item.summary || ''].filter(Boolean).join(' — ').slice(0, 500);
});
addList('Layer 4 openFDA results', results.openfda, (item) => {
  return [item.k_number, item.product_code, item.device_name, item.decision_code, item.decision_date].filter(Boolean).join(' | ');
});
addList('Layer 4 KR law/data.go.kr results', results.law_kr || results.data_go_kr, (item) => {
  return [item.summary || item.title || '', item.law_name || item.service || ''].filter(Boolean).join(' — ').slice(0, 500);
});

let layer4Context = '';
if (sections.length > 0) {
  layer4Context = '\n--- REAL-TIME REGULATORY DATA (Layer 4, reference only) ---\n' + sections.join('\n') + '\n--- END REAL-TIME REGULATORY DATA ---';
} else {
  const status = lookup.status || (lookup.error ? 'lookup_failed' : 'empty_or_unavailable');
  layer4Context = '\n--- REAL-TIME REGULATORY DATA (Layer 4) ---\nNo live result available; continue with static KB and escalate uncertainty. status=' + status + '\n--- END REAL-TIME REGULATORY DATA ---';
}

return [{
  json: {
    ...base,
    layer4_context: layer4Context,
    layer4_status: lookup.status || (lookup.error ? 'lookup_failed' : 'unknown'),
    layer4_result_counts: {
      llm_wiki: Array.isArray(results.llm_wiki) ? results.llm_wiki.length : 0,
      openfda: Array.isArray(results.openfda) ? results.openfda.length : 0,
      law_kr: Array.isArray(results.law_kr) ? results.law_kr.length : 0,
      data_go_kr: Array.isArray(results.data_go_kr) ? results.data_go_kr.length : 0
    }
  }
}];
